<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>View config</title>
  <script>
  (function(){try{if(!window.parent||window.parent===window)return;var ps=window.parent.getComputedStyle(window.parent.document.documentElement);Array.from(ps).filter(function(p){return p.indexOf("--")===0}).forEach(function(n){var v=ps.getPropertyValue(n);if(v!=null&&String(v).trim()!=="")document.documentElement.style.setProperty(n,String(v).trim());});}catch(_){}})();
  </script>
  <style>
    html { color-scheme: light dark; }
    html, body {
      margin: 0;
      min-height: 100%;
      font-family: Avenir, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      font-size: 13px;
      line-height: 1.45;
      background-color: rgb(var(--v-theme-cfxbackground, 250, 250, 250));
      color: rgb(var(--v-theme-cfxtext, 33, 33, 33));
    }
    @media (prefers-color-scheme: dark) {
      html, body {
        background-color: rgb(var(--v-theme-cfxbackground, 22, 24, 28));
        color: rgb(var(--v-theme-cfxtext, 250, 250, 250));
      }
    }
    .bar {
      padding: 12px 16px;
      border-bottom: 1px solid rgba(var(--v-theme-cfxgrey, 189, 189, 189), 0.35);
      background: rgb(var(--v-theme-cfxcard, 245, 245, 245));
      font-weight: 600;
      font-size: 15px;
    }
    @media (prefers-color-scheme: dark) {
      .bar {
        background: rgb(var(--v-theme-cfxcard, 40, 42, 48));
        border-bottom-color: rgba(255, 255, 255, 0.12);
      }
    }
    .wrap { padding: 16px 18px; }
    pre {
      white-space: pre-wrap;
      word-break: break-word;
      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
      font-size: 13px;
    }
    .err { color: rgb(var(--v-theme-error, 198, 40, 40)); font-size: 13px; }
    textarea#cfg-raw { position: absolute; left: -9999px; width: 1px; height: 1px; opacity: 0; pointer-events: none; }
  </style>
</head>
<body>
  <div class="bar">View config</div>
  <div class="wrap">
    {%- if config_id == "" -%}
      <div class="err">Missing config_id in dashboard context.</div>
    {%- else -%}
      <textarea id="cfg-raw" aria-hidden="true">{{ rhs_output | default("") | e }}</textarea>
      <pre id="cfg-out"></pre>
      <script>
      (function () {
        function cleanConfigText(text) {
          if (text == null || text === '') return 'No configuration found';
          var lines = String(text).split(/\r?\n/);

          function isBuildingConfigLine(t) {
            if (/^building configuration[\s.\u2026]*$/i.test(t)) return true;
            if (/^\!\!+\s*building configuration/i.test(t)) return true;
            if (/^\!\s*building configuration/i.test(t)) return true;
            return false;
          }

          function isWeekdayUtcTimestampLine(t) {
            return /^(Mon|Tue|Wed|Thu|Fri|Sat|Sun)\s+.+\s+UTC\s*$/i.test(t);
          }

          var firstBuilding = -1;
          for (var j = 0; j < lines.length; j++) {
            if (isBuildingConfigLine(lines[j].trim())) {
              firstBuilding = j;
              break;
            }
          }

          var out = [];
          for (var i = 0; i < lines.length; i++) {
            var line = lines[i];
            var t = line.trim();
            if (isBuildingConfigLine(t)) continue;
            if (firstBuilding >= 0 && isWeekdayUtcTimestampLine(t) && i < firstBuilding) continue;
            out.push(line);
          }
          var s = out.join('\n').replace(/^\n+/, '');
          return s === '' ? 'No configuration found' : s;
        }
        try {
          var ta = document.getElementById('cfg-raw');
          var raw = ta ? ta.value : '';
          var pre = document.getElementById('cfg-out');
          if (pre) pre.textContent = cleanConfigText(raw);
        } catch (e) {
          var pre = document.getElementById('cfg-out');
          if (pre) pre.textContent = 'Unable to display configuration.';
        }
      })();
      </script>
    {%- endif -%}
  </div>
</body>
</html>
